  'b.externalDb.init({',
  '  backends: {',
  '    primary: {',
  '      connect:  async () =&gt; { var c = new pg.Client({ connectionString: env("DB_URL") }); await c.connect(); return c; },',
  '      query:    async (c, sql, params) =&gt; { var r = await c.query(sql, params); return { rows: r.rows, rowCount: r.rowCount }; },',
  '      close:    async (c) =&gt; { await c.end(); },',
  '      pool:     { min: 2, max: 20 },',
  '      residencyTag: "US",',
  '    },',
  '  },',
  '});',
  '',
  '// App-data queries route through b.externalDb (NOT b.db.from):',
  'var { rows } = await b.externalDb.query("SELECT * FROM products WHERE id = $1", [id]);',
  '',
  '// Multi-statement transaction (rollback on throw):',
  'await b.externalDb.transaction(async function (tx) {',
  '  await tx.query("INSERT INTO orders (id, total) VALUES ($1, $2)", [orderId, 99]);',
  '  await tx.query("UPDATE inventory SET qty = qty - 1 WHERE sku = $1", [sku]);',
